diff --git a/src/Config.php b/src/Config.php
index becf047..19fdd15 100644
--- a/src/Config.php
+++ b/src/Config.php
@@ -32,7 +32,20 @@ class Config

     public function extend(array $options): Config
     {
-        return new Config(array_merge($this->options, $options));
+        return new Config($this->deepMerge($this->options, $options));
+    }
+
+    private function deepMerge(array $base, array $override): array
+    {
+        foreach ($override as $key => $value) {
+            if (is_string($key) && isset($base[$key]) && is_array($base[$key]) && is_array($value)) {
+                $base[$key] = $this->deepMerge($base[$key], $value);
+            } else {
+                $base[$key] = $value;
+            }
+        }
+
+        return $base;
+    }
